    DEUTERIUM               to Details (type = ElementType.Atom,        symbol = "²H",          label = "DEUTERIUM (²H)",       mass = 2f, e = 1, p = 1, n = 1,      description = "Дейтерий"),
    HELIUM_3                to Details (type = ElementType.Atom,        symbol = "³He",         label = "Helium (³He)",         mass = 3f, e = 2, p = 2, n = 1,      description = "Гелий", alphaGammaResult = BERYLLIUM_7),
    HELIUM_4                to Details (type = ElementType.Atom,        symbol = "⁴He",         label = "Helium (⁴He)",         mass = 4f, e = 2, p = 2, n = 2,      description = "Гелий", alphaGammaResult = BERYLLIUM_8),
    LITHIUM_7               to Details (type = ElementType.Atom,        symbol = "⁷Li",         label = "Lithium (⁷Li)",        mass = 7f, e = 3, p = 3, n = 4,      description = "Литий", protonNeutronResult = BERYLLIUM_7, neutronGammaResult = LITHIUM_8),
    // ⁸Li — продукт ⁷Li(n,γ)⁸Li (минорная нейтрон-избыточная ветка). β⁻-нестабилен (t½ 0.84 с): ⁸Li → ⁸Be (→ 2α). energyLevels берёт лестницу Z=3.
